const body = $input.first().json.body || $input.first().json;

const stats = body.stats || {};
const lastActivity = body.lastActivity || null;
const bodyStats = body.bodyStats || {};

const week = stats.week || {};
const month = stats.month || {};
const year = stats.year || {};

let prompt = `Du bist ein persönlicher Fitness-Coach für Dennis. Analysiere seine aktuellen Sportstats und gib eine kurze, motivierende Zusammenfassung auf Deutsch.

DIESE WOCHE:
- ${week.count||0} Aktivitäten, ${week.distanceKm||0} km, ${week.timeMin||0} Min, ${week.elevationM||0}m Höhe
- Sportarten: ${(week.byType||[]).map(t=>t.label+' '+t.distanceKm+'km').join(', ')||'keine'}

DIESEN MONAT:
- ${month.count||0} Aktivitäten, ${month.distanceKm||0} km, ${month.timeMin||0} Min

DIESES JAHR:
- ${year.count||0} Aktivitäten, ${year.distanceKm||0} km total`;

if (lastActivity) {
  prompt += `\n\nLETZTES TRAINING: ${lastActivity.name} (${lastActivity.label}), ${lastActivity.distanceKm}km, ${lastActivity.timeMin} Min`;
  if (lastActivity.avgHr) prompt += `, Ø ${lastActivity.avgHr} bpm`;
  if (lastActivity.calories) prompt += `, ${lastActivity.calories} kcal`;
}

const weight = bodyStats.body_mass && bodyStats.body_mass[0];
const bodyFat = bodyStats.body_fat_percentage && bodyStats.body_fat_percentage[0];
if (weight) prompt += `\n\nGEWICHT: ${weight.value} kg`;
if (bodyFat) prompt += `, Körperfett: ${bodyFat.value}%`;

prompt += `\n\nGib genau zurück:
{
  "summary": "2-3 Sätze motivierende Zusammenfassung des aktuellen Fitnessstands",
  "tip": "1 konkreter Trainingstipp für diese Woche",
  "mood": "emoji das die aktuelle Fitness-Phase beschreibt (1 emoji)"
}

Antworte NUR mit dem JSON-Objekt, nichts anderes.`;

return [{ json: { prompt } }];

const j = $input.first().json;
let raw = '';
if (Array.isArray(j.content)) {
  raw = j.content.map(c => c.text || '').join('');
} else {
  raw = String(j.content || j.text || '');
}
let result = { summary: '', tip: '', mood: '💪' };
try {
  const match = raw.match(/\{[\s\S]*\}/);
  if (match) result = { ...result, ...JSON.parse(match[0]) };
} catch(e) {
  result.summary = raw.slice(0, 300);
}
return [{ json: result }];

